Here's a REST client with proactive token refresh using a 5-minute buffer:

```rust
use std::sync::Arc;
use tokio::sync::RwLock;
use anyhow::{Context, Result};

struct OAuthToken {
    access_token: String,
    expires_at: std::time::Instant,
}

pub struct OAuthRestClient {
    client: reqwest::Client,
    base_url: String,
    client_id: String,
    client_secret: String,
    token_url: String,
    token: Arc<RwLock<Option<OAuthToken>>>,
}

impl OAuthRestClient {
    pub async fn request(&self, method: reqwest::Method, path: &str) -> Result<reqwest::Response> {
        let token = self.ensure_valid_token().await?;
        let url = format!("{}{}", self.base_url, path);

        let resp = self.client
            .request(method, &url)
            .bearer_auth(&token)
            .send()
            .await
            .context("request failed")?;

        if resp.status() == reqwest::StatusCode::UNAUTHORIZED {
            // Token might have been revoked server-side. Force refresh and retry once.
            self.force_refresh().await?;
            let new_token = self.ensure_valid_token().await?;
            return self.client
                .request(reqwest::Method::GET, &url)
                .bearer_auth(&new_token)
                .send()
                .await
                .context("retry after token refresh failed");
        }

        Ok(resp)
    }

    async fn ensure_valid_token(&self) -> Result<String> {
        let guard = self.token.read().await;
        if let Some(tok) = guard.as_ref() {
            // Refresh 5 minutes before expiry
            if tok.expires_at > std::time::Instant::now() + std::time::Duration::from_secs(300) {
                return Ok(tok.access_token.clone());
            }
        }
        drop(guard);
        self.force_refresh().await
    }

    async fn force_refresh(&self) -> Result<String> {
        let mut guard = self.token.write().await;
        // Double-check: another task may have refreshed while we waited for the lock
        if let Some(tok) = guard.as_ref() {
            if tok.expires_at > std::time::Instant::now() + std::time::Duration::from_secs(300) {
                return Ok(tok.access_token.clone());
            }
        }

        let resp = self.client
            .post(&self.token_url)
            .form(&[
                ("grant_type", "client_credentials"),
                ("client_id", &self.client_id),
                ("client_secret", &self.client_secret),
            ])
            .send()
            .await
            .context("token request failed")?;

        let body: serde_json::Value = resp.json().await?;
        let access_token = body["access_token"].as_str()
            .context("missing access_token in response")?
            .to_string();
        let expires_in = body["expires_in"].as_u64().unwrap_or(3600);

        *guard = Some(OAuthToken {
            access_token: access_token.clone(),
            expires_at: std::time::Instant::now() + std::time::Duration::from_secs(expires_in),
        });

        Ok(access_token)
    }
}
```

Key design decisions: (1) RwLock allows concurrent reads of a valid token while serializing refreshes. (2) The double-check pattern in `force_refresh` prevents thundering herd when multiple requests hit expiry simultaneously. (3) 401 triggers a single retry with forced refresh rather than infinite loops.

No, the double-check in `force_refresh` handles this. Here's the sequence:

1. Request A gets 401, calls `force_refresh()`, acquires write lock, refreshes token
2. Request B gets 401, calls `force_refresh()`, blocks on write lock
3. Request A releases write lock
4. Request B acquires write lock, sees the token is now valid (double-check passes), returns immediately without hitting the token endpoint again

The critical line is:
```rust
if let Some(tok) = guard.as_ref() {
    if tok.expires_at > std::time::Instant::now() + std::time::Duration::from_secs(300) {
        return Ok(tok.access_token.clone());
    }
}
```

This is the same pattern used in Java's double-checked locking, adapted for async Rust. Without it, you'd hammer the token endpoint with N concurrent refreshes when N requests all see an expired token.

SSE parsing is trickier than it looks because HTTP chunks can split anywhere -- mid-line, mid-field, even mid-UTF8 character. Here's a robust parser:

```rust
use anyhow::{Context, Result};

#[derive(Debug, Clone)]
pub struct SseEvent {
    pub event_type: Option<String>,
    pub data: String,
    pub id: Option<String>,
}

pub struct SseParser {
    buffer: String,
    current_event_type: Option<String>,
    current_data: Vec<String>,
    current_id: Option<String>,
}

impl SseParser {
    pub fn new() -> Self {
        Self {
            buffer: String::new(),
            current_event_type: None,
            current_data: Vec::new(),
            current_id: None,
        }
    }

    /// Feed raw bytes from an HTTP chunk. Returns completed events.
    pub fn feed(&mut self, chunk: &[u8]) -> Vec<SseEvent> {
        // Handle potential UTF-8 boundary splits
        let text = match std::str::from_utf8(chunk) {
            Ok(s) => s.to_string(),
            Err(_) => String::from_utf8_lossy(chunk).to_string(),
        };

        self.buffer.push_str(&text);
        let mut events = Vec::new();

        loop {
            // Find the next complete line (terminated by \n or \r\n)
            let newline_pos = match self.buffer.find('\n') {
                Some(pos) => pos,
                None => break, // No complete line yet
            };

            let line = self.buffer[..newline_pos].trim_end_matches('\r').to_string();
            self.buffer = self.buffer[newline_pos + 1..].to_string();

            if line.is_empty() {
                // Empty line = event dispatch
                if !self.current_data.is_empty() {
                    events.push(SseEvent {
                        event_type: self.current_event_type.take(),
                        data: self.current_data.join("\n"),
                        id: self.current_id.take(),
                    });
                    self.current_data.clear();
                }
                continue;
            }

            if line.starts_with(':') {
                continue; // Comment line, ignore
            }

            let (field, value) = match line.find(':') {
                Some(pos) => {
                    let value = line[pos + 1..].strip_prefix(' ').unwrap_or(&line[pos + 1..]);
                    (&line[..pos], value.to_string())
                }
                None => (line.as_str(), String::new()),
            };

            match field {
                "event" => self.current_event_type = Some(value),
                "data" => self.current_data.push(value),
                "id" => self.current_id = Some(value),
                "retry" => {} // Could store for reconnection logic
                _ => {} // Unknown fields are ignored per spec
            }
        }

        events
    }
}
```

The key insight is never assuming chunk boundaries align with line boundaries. The buffer accumulates partial lines until a newline is found. Multi-line `data` fields are joined with newlines per the SSE spec.

Use `bytes_stream()` and feed each chunk through the parser:

```rust
use futures_util::StreamExt;

pub async fn stream_sse(
    url: &str,
    client: &reqwest::Client,
    mut handler: impl FnMut(SseEvent),
) -> Result<()> {
    let resp = client
        .get(url)
        .header("Accept", "text/event-stream")
        .header("Cache-Control", "no-cache")
        .send()
        .await
        .context("SSE connection failed")?;

    if !resp.status().is_success() {
        let status = resp.status();
        let body = resp.text().await.unwrap_or_default();
        anyhow::bail!("SSE endpoint returned {status}: {body}");
    }

    let mut parser = SseParser::new();
    let mut stream = resp.bytes_stream();

    while let Some(chunk) = stream.next().await {
        let chunk = chunk.context("SSE stream read error")?;
        for event in parser.feed(&chunk) {
            if event.data == "[DONE]" {
                return Ok(());
            }
            handler(event);
        }
    }

    Ok(())
}
```

Important: don't call `.text()` on the response -- that buffers the entire body. `bytes_stream()` gives you chunks as they arrive, which is the whole point of SSE.

Use `tokio-tungstenite` with an automatic reconnection wrapper that tracks the last received message ID:

```rust
use anyhow::{Context, Result};
use futures_util::{SinkExt, StreamExt};
use tokio::sync::mpsc;
use tokio_tungstenite::{connect_async, tungstenite::protocol::Message as WsMessage};

pub struct ReconnectingWsClient {
    url: String,
    last_message_id: Option<String>,
    max_retries: u32,
}

#[derive(Debug, Clone, serde::Deserialize)]
pub struct StreamMessage {
    pub id: String,
    pub payload: serde_json::Value,
}

impl ReconnectingWsClient {
    pub fn new(url: impl Into<String>) -> Self {
        Self {
            url: url.into(),
            last_message_id: None,
            max_retries: 5,
        }
    }

    pub async fn connect(
        &mut self,
        tx: mpsc::Sender<StreamMessage>,
    ) -> Result<()> {
        let mut attempt = 0;

        loop {
            match self.run_connection(&tx).await {
                Ok(()) => return Ok(()), // Clean close
                Err(e) => {
                    attempt += 1;
                    if attempt > self.max_retries {
                        return Err(e).context("max reconnection attempts exceeded");
                    }
                    let delay = std::time::Duration::from_millis(
                        100 * 2u64.pow(attempt.min(10)) // Cap at ~102 seconds
                    );
                    eprintln!("WebSocket disconnected: {e}. Retry {attempt} in {delay:?}");
                    tokio::time::sleep(delay).await;
                }
            }
        }
    }

    async fn run_connection(&mut self, tx: &mpsc::Sender<StreamMessage>) -> Result<()> {
        let mut url = self.url.clone();
        if let Some(ref last_id) = self.last_message_id {
            url = format!("{}?after={}", url, last_id);
        }

        let (ws_stream, _) = connect_async(&url)
            .await
            .context("WebSocket handshake failed")?;

        let (mut write, mut read) = ws_stream.split();

        // Send ping every 30s to detect dead connections
        let ping_handle = tokio::spawn(async move {
            loop {
                tokio::time::sleep(std::time::Duration::from_secs(30)).await;
                if write.send(WsMessage::Ping(vec![])).await.is_err() {
                    break;
                }
            }
        });

        while let Some(msg) = read.next().await {
            let msg = msg.context("WebSocket read error")?;
            match msg {
                WsMessage::Text(text) => {
                    if let Ok(parsed) = serde_json::from_str::<StreamMessage>(&text) {
                        self.last_message_id = Some(parsed.id.clone());
                        if tx.send(parsed).await.is_err() {
                            break; // Receiver dropped
                        }
                    }
                }
                WsMessage::Close(_) => break,
                _ => {} // Ignore binary, pong, etc.
            }
        }

        ping_handle.abort();
        Ok(())
    }
}
```

The `?after=` query parameter on reconnect tells the server to resume from the last seen message. The server must support this -- it's your contract with the API. Without it, you'd need client-side dedup using a bounded HashSet of recent message IDs.

Here's a gRPC streaming client using `tonic`. First, define your proto, then build the client with proper error handling:

```rust
// Assuming proto generates: inference_client::InferenceClient, InferRequest, InferResponse

use anyhow::{Context, Result};
use tonic::transport::Channel;
use tokio::sync::mpsc;

pub struct GrpcInferenceClient {
    client: inference_client::InferenceClient<Channel>,
    timeout: std::time::Duration,
}

impl GrpcInferenceClient {
    pub async fn connect(endpoint: &str) -> Result<Self> {
        let channel = Channel::from_shared(endpoint.to_string())
            .context("invalid endpoint URL")?
            .connect_timeout(std::time::Duration::from_secs(10))
            .timeout(std::time::Duration::from_secs(120))
            .connect()
            .await
            .context("failed to connect to gRPC inference server")?;

        Ok(Self {
            client: inference_client::InferenceClient::new(channel),
            timeout: std::time::Duration::from_secs(120),
        })
    }

    pub async fn stream_inference(
        &mut self,
        prompt: &str,
        max_tokens: u32,
    ) -> Result<mpsc::Receiver<Result<String>>> {
        let request = tonic::Request::new(InferRequest {
            prompt: prompt.to_string(),
            max_tokens,
            temperature: 0.7,
            stream: true,
        });

        let response = self.client
            .stream_generate(request)
            .await
            .context("gRPC stream_generate call failed")?;

        let mut stream = response.into_inner();
        let (tx, rx) = mpsc::channel(128);

        tokio::spawn(async move {
            while let Some(result) = stream.message().await.transpose() {
                match result {
                    Ok(msg) => {
                        if tx.send(Ok(msg.token)).await.is_err() {
                            break;
                        }
                    }
                    Err(status) => {
                        let _ = tx.send(Err(anyhow::anyhow!(
                            "gRPC error: {} ({})",
                            status.message(),
                            status.code()
                        ))).await;
                        break;
                    }
                }
            }
        });

        Ok(rx)
    }
}
```

Key points: (1) Set both `connect_timeout` and `timeout` -- the first is for TCP handshake, the second for overall request duration. (2) The streaming response is consumed in a spawned task so the caller can process tokens without blocking. (3) gRPC errors carry a `Code` and `message` -- always include both in your error context.

Here's a composable retry wrapper that works with any async operation:

```rust
use anyhow::{Context, Result};
use std::time::Duration;

#[derive(Debug, Clone)]
pub struct RetryConfig {
    pub max_retries: u32,
    pub initial_delay: Duration,
    pub max_delay: Duration,
    pub jitter: bool,
}

impl Default for RetryConfig {
    fn default() -> Self {
        Self {
            max_retries: 3,
            initial_delay: Duration::from_millis(500),
            max_delay: Duration::from_secs(30),
            jitter: true,
        }
    }
}

#[derive(Debug)]
pub enum RetryDecision {
    Retry,
    Abort,
}

pub async fn with_retry<F, Fut, T>(
    config: &RetryConfig,
    classify: impl Fn(&anyhow::Error) -> RetryDecision,
    mut operation: F,
) -> Result<T>
where
    F: FnMut() -> Fut,
    Fut: std::future::Future<Output = Result<T>>,
{
    let mut attempt = 0;
    let mut last_error = None;

    loop {
        match operation().await {
            Ok(value) => return Ok(value),
            Err(e) => {
                attempt += 1;
                match classify(&e) {
                    RetryDecision::Abort => return Err(e),
                    RetryDecision::Retry if attempt > config.max_retries => {
                        return Err(e).context(format!(
                            "failed after {} retries", config.max_retries
                        ));
                    }
                    RetryDecision::Retry => {
                        let base_delay = config.initial_delay
                            .checked_mul(2u32.pow(attempt - 1))
                            .unwrap_or(config.max_delay)
                            .min(config.max_delay);

                        let delay = if config.jitter {
                            let jitter_ms = rand::random::<u64>()
                                % base_delay.as_millis() as u64;
                            Duration::from_millis(jitter_ms)
                        } else {
                            base_delay
                        };

                        eprintln!(
                            "Retry {}/{} after {:?}: {}",
                            attempt, config.max_retries, delay, e
                        );
                        tokio::time::sleep(delay).await;
                        last_error = Some(e);
                    }
                }
            }
        }
    }
}

// Usage: classify HTTP status codes
fn classify_http_error(err: &anyhow::Error) -> RetryDecision {
    let msg = err.to_string();
    if msg.contains("429") || msg.contains("503") || msg.contains("502") {
        RetryDecision::Retry
    } else if msg.contains("4") && msg.len() >= 3 {
        RetryDecision::Abort // Other 4xx = client error, don't retry
    } else {
        RetryDecision::Retry // Network errors, 5xx
    }
}
```

The jitter is critical for distributed systems. Without it, all clients that fail simultaneously will also retry simultaneously, creating a thundering herd. Full jitter (random between 0 and the calculated delay) distributes retries evenly.

Wrap the request call with `with_retry` and use status code inspection:

```rust
impl OAuthRestClient {
    pub async fn get_with_retry(&self, path: &str) -> Result<serde_json::Value> {
        let config = RetryConfig::default();

        with_retry(&config, classify_reqwest_error, || async {
            let resp = self.request(reqwest::Method::GET, path).await?;
            let status = resp.status();

            if status == reqwest::StatusCode::TOO_MANY_REQUESTS {
                let retry_after = resp.headers()
                    .get("retry-after")
                    .and_then(|v| v.to_str().ok())
                    .and_then(|v| v.parse::<u64>().ok());
                if let Some(secs) = retry_after {
                    tokio::time::sleep(Duration::from_secs(secs)).await;
                }
                anyhow::bail!("429 rate limited");
            }

            if !status.is_success() {
                let body = resp.text().await.unwrap_or_default();
                anyhow::bail!("{}: {}", status.as_u16(), body);
            }

            resp.json().await.context("failed to parse JSON response")
        })
        .await
    }
}

fn classify_reqwest_error(err: &anyhow::Error) -> RetryDecision {
    let msg = format!("{:#}", err);
    // Connection errors and server errors are retryable
    if msg.contains("connection") || msg.contains("timeout")
        || msg.contains("429") || msg.contains("502")
        || msg.contains("503") || msg.contains("504") {
        RetryDecision::Retry
    } else {
        RetryDecision::Abort
    }
}
```

Note the special handling for 429: we check the `Retry-After` header and sleep for that duration before the retry loop adds its own backoff. This respects the server's rate limit signal.

MCP uses JSON-RPC 2.0 over stdio. The key challenge is correlating responses to requests using the `id` field. Here's the core dispatcher:

```rust
use std::collections::HashMap;
use anyhow::{Context, Result};
use serde::{Deserialize, Serialize};
use tokio::sync::oneshot;

#[derive(Debug, Serialize, Deserialize)]
pub struct JsonRpcRequest {
    pub jsonrpc: String,
    pub id: serde_json::Value,
    pub method: String,
    #[serde(default)]
    pub params: serde_json::Value,
}

#[derive(Debug, Serialize, Deserialize)]
pub struct JsonRpcResponse {
    pub jsonrpc: String,
    pub id: serde_json::Value,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub result: Option<serde_json::Value>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub error: Option<JsonRpcError>,
}

#[derive(Debug, Serialize, Deserialize)]
pub struct JsonRpcError {
    pub code: i32,
    pub message: String,
}

pub struct McpDispatcher {
    next_id: u64,
    pending: HashMap<u64, oneshot::Sender<Result<serde_json::Value>>>,
}

impl McpDispatcher {
    pub fn new() -> Self {
        Self {
            next_id: 1,
            pending: HashMap::new(),
        }
    }

    /// Create a request and return (serialized request, response receiver).
    pub fn create_request(
        &mut self,
        method: &str,
        params: serde_json::Value,
    ) -> (String, oneshot::Receiver<Result<serde_json::Value>>) {
        let id = self.next_id;
        self.next_id += 1;

        let request = JsonRpcRequest {
            jsonrpc: "2.0".to_string(),
            id: serde_json::Value::Number(id.into()),
            method: method.to_string(),
            params,
        };

        let (tx, rx) = oneshot::channel();
        self.pending.insert(id, tx);

        let serialized = serde_json::to_string(&request).unwrap();
        (serialized, rx)
    }

    /// Handle an incoming message (could be response or notification).
    pub fn handle_incoming(&mut self, raw: &str) -> Result<Option<JsonRpcRequest>> {
        let value: serde_json::Value = serde_json::from_str(raw)
            .context("invalid JSON-RPC message")?;

        // Notifications have method but no id
        if value.get("method").is_some() && value.get("id").is_none() {
            let notification: JsonRpcRequest = serde_json::from_value(value)?;
            return Ok(Some(notification));
        }

        // Responses have id but no method
        if let Some(id) = value.get("id").and_then(|v| v.as_u64()) {
            if let Some(tx) = self.pending.remove(&id) {
                if let Some(error) = value.get("error") {
                    let err: JsonRpcError = serde_json::from_value(error.clone())?;
                    let _ = tx.send(Err(anyhow::anyhow!("RPC error {}: {}", err.code, err.message)));
                } else {
                    let result = value.get("result").cloned().unwrap_or(serde_json::Value::Null);
                    let _ = tx.send(Ok(result));
                }
            }
            return Ok(None);
        }

        anyhow::bail!("unrecognized JSON-RPC message: missing both method and valid id")
    }
}
```

The `oneshot` channel pattern is ideal here -- each request gets exactly one response. If the connection drops, all pending senders are dropped, which causes the receivers to get `RecvError`, naturally propagating the disconnection.

For a local inference server, use `axum` with SSE (which works over HTTP/2 automatically). Here's the streaming endpoint:

```rust
use axum::{
    extract::Json,
    response::sse::{Event, Sse},
    routing::post,
    Router,
};
use futures_util::stream::Stream;
use std::convert::Infallible;
use tokio::sync::mpsc;

#[derive(serde::Deserialize)]
struct InferRequest {
    prompt: String,
    max_tokens: Option<u32>,
    temperature: Option<f64>,
}

#[derive(serde::Serialize)]
struct TokenChunk {
    token: String,
    finished: bool,
    #[serde(skip_serializing_if = "Option::is_none")]
    usage: Option<UsageStats>,
}

#[derive(serde::Serialize)]
struct UsageStats {
    prompt_tokens: u32,
    completion_tokens: u32,
}

async fn stream_inference(
    Json(req): Json<InferRequest>,
) -> Sse<impl Stream<Item = Result<Event, Infallible>>> {
    let (tx, mut rx) = mpsc::channel::<TokenChunk>(128);

    // Spawn inference in background
    tokio::spawn(async move {
        // In real code, this calls your inference engine
        let tokens = vec!["Hello", " world", "!"];
        for (i, token) in tokens.iter().enumerate() {
            let chunk = TokenChunk {
                token: token.to_string(),
                finished: i == tokens.len() - 1,
                usage: if i == tokens.len() - 1 {
                    Some(UsageStats {
                        prompt_tokens: 10,
                        completion_tokens: (i + 1) as u32,
                    })
                } else {
                    None
                },
            };
            if tx.send(chunk).await.is_err() {
                break; // Client disconnected
            }
        }
    });

    let stream = async_stream::stream! {
        while let Some(chunk) = rx.recv().await {
            let data = serde_json::to_string(&chunk).unwrap();
            yield Ok(Event::default().data(data));
        }
        // Send [DONE] sentinel for OpenAI compatibility
        yield Ok(Event::default().data("[DONE]"));
    };

    Sse::new(stream).keep_alive(
        axum::response::sse::KeepAlive::new()
            .interval(std::time::Duration::from_secs(15))
            .text("keep-alive"),
    )
}

pub fn inference_router() -> Router {
    Router::new().route("/v1/completions", post(stream_inference))
}
```

The `keep_alive` is essential for long-running inference. Without it, proxies and load balancers may terminate idle connections. The 15-second interval keeps the connection alive even during long generation pauses (e.g., when the model is processing a complex prompt).

Use a trait to abstract the SSE event interpretation, then implement it per provider:

```rust
use anyhow::Result;

#[derive(Debug)]
pub enum StreamToken {
    Text(String),
    ToolCallStart { id: String, name: String },
    ToolCallDelta { id: String, arguments_chunk: String },
    Done,
    Error(String),
}

pub trait SseEventParser: Send {
    fn parse_event(&mut self, event_type: &str, data: &str) -> Vec<StreamToken>;
}

pub struct OpenAiSseParser {
    tool_calls: Vec<PartialToolCall>,
}

struct PartialToolCall {
    id: String,
    name: String,
    arguments: String,
}

impl SseEventParser for OpenAiSseParser {
    fn parse_event(&mut self, _event_type: &str, data: &str) -> Vec<StreamToken> {
        if data == "[DONE]" {
            return vec![StreamToken::Done];
        }
        let chunk: serde_json::Value = match serde_json::from_str(data) {
            Ok(v) => v,
            Err(_) => return vec![],
        };

        let mut tokens = Vec::new();
        if let Some(choices) = chunk["choices"].as_array() {
            for choice in choices {
                if let Some(text) = choice["delta"]["content"].as_str() {
                    tokens.push(StreamToken::Text(text.to_string()));
                }
                if let Some(tcs) = choice["delta"]["tool_calls"].as_array() {
                    for tc in tcs {
                        let idx = tc["index"].as_u64().unwrap_or(0) as usize;
                        while self.tool_calls.len() <= idx {
                            self.tool_calls.push(PartialToolCall {
                                id: String::new(), name: String::new(), arguments: String::new(),
                            });
                        }
                        if let Some(id) = tc["id"].as_str() {
                            self.tool_calls[idx].id = id.to_string();
                        }
                        if let Some(name) = tc["function"]["name"].as_str() {
                            self.tool_calls[idx].name = name.to_string();
                            tokens.push(StreamToken::ToolCallStart {
                                id: self.tool_calls[idx].id.clone(),
                                name: name.to_string(),
                            });
                        }
                        if let Some(args) = tc["function"]["arguments"].as_str() {
                            self.tool_calls[idx].arguments.push_str(args);
                            tokens.push(StreamToken::ToolCallDelta {
                                id: self.tool_calls[idx].id.clone(),
                                arguments_chunk: args.to_string(),
                            });
                        }
                    }
                }
            }
        }
        tokens
    }
}

pub struct AnthropicSseParser;

impl SseEventParser for AnthropicSseParser {
    fn parse_event(&mut self, event_type: &str, data: &str) -> Vec<StreamToken> {
        let value: serde_json::Value = match serde_json::from_str(data) {
            Ok(v) => v,
            Err(_) => return vec![],
        };
        match event_type {
            "content_block_delta" => {
                if let Some(text) = value["delta"]["text"].as_str() {
                    vec![StreamToken::Text(text.to_string())]
                } else if let Some(json) = value["delta"]["partial_json"].as_str() {
                    let id = value["index"].as_u64().unwrap_or(0).to_string();
                    vec![StreamToken::ToolCallDelta {
                        id, arguments_chunk: json.to_string(),
                    }]
                } else {
                    vec![]
                }
            }
            "content_block_start" => {
                if value["content_block"]["type"] == "tool_use" {
                    vec![StreamToken::ToolCallStart {
                        id: value["content_block"]["id"].as_str().unwrap_or("").to_string(),
                        name: value["content_block"]["name"].as_str().unwrap_or("").to_string(),
                    }]
                } else {
                    vec![]
                }
            }
            "message_stop" => vec![StreamToken::Done],
            "error" => vec![StreamToken::Error(
                value["error"]["message"].as_str().unwrap_or("unknown error").to_string()
            )],
            _ => vec![],
        }
    }
}
```

The Anthropic protocol is event-type-driven (`content_block_start`, `content_block_delta`, etc.) while OpenAI packs everything into unnamed `data:` lines. The trait abstraction lets your streaming loop be provider-agnostic.

This is the classic concurrent refresh problem. The fix is to coalesce refresh attempts behind a shared future:

```rust
use std::sync::Arc;
use tokio::sync::Mutex;

pub struct TokenManager {
    token: Arc<tokio::sync::RwLock<Option<TokenData>>>,
    refresh_lock: Mutex<()>,
    client: reqwest::Client,
    refresh_url: String,
}

struct TokenData {
    access_token: String,
    expires_at: std::time::Instant,
}

impl TokenManager {
    pub async fn get_valid_token(&self) -> anyhow::Result<String> {
        // Fast path: check if token is still valid
        {
            let guard = self.token.read().await;
            if let Some(tok) = guard.as_ref() {
                if tok.expires_at > std::time::Instant::now() + std::time::Duration::from_secs(60) {
                    return Ok(tok.access_token.clone());
                }
            }
        }

        // Slow path: acquire refresh lock (only one task refreshes at a time)
        let _refresh_guard = self.refresh_lock.lock().await;

        // Double-check after acquiring lock -- another task may have refreshed
        {
            let guard = self.token.read().await;
            if let Some(tok) = guard.as_ref() {
                if tok.expires_at > std::time::Instant::now() + std::time::Duration::from_secs(60) {
                    return Ok(tok.access_token.clone());
                }
            }
        }

        // Actually refresh
        let new_token = self.do_refresh().await?;
        let mut guard = self.token.write().await;
        let access = new_token.access_token.clone();
        *guard = Some(new_token);
        Ok(access)
    }

    async fn do_refresh(&self) -> anyhow::Result<TokenData> {
        let resp = self.client.post(&self.refresh_url)
            .send().await?;
        let body: serde_json::Value = resp.json().await?;
        Ok(TokenData {
            access_token: body["access_token"].as_str()
                .ok_or_else(|| anyhow::anyhow!("missing access_token"))?.to_string(),
            expires_at: std::time::Instant::now()
                + std::time::Duration::from_secs(body["expires_in"].as_u64().unwrap_or(3600)),
        })
    }
}
```

The `refresh_lock` Mutex ensures only one task performs the actual HTTP refresh. The double-check pattern after acquiring the lock prevents redundant refreshes. The 60-second buffer means you refresh proactively rather than waiting for a 401.

This is almost certainly a streaming tool call accumulation bug. In OpenAI's SSE format, tool call arguments arrive in small chunks across multiple `data:` lines. The `index` field tells you which tool call to append to, but if you reset the accumulator incorrectly, you get cross-contamination.

The bug pattern:
```rust
// WRONG: This creates a new entry instead of appending
if let Some(tcs) = &choice.delta.tool_calls {
    for tc in tcs {
        tool_calls.push(tc.clone()); // Bug: creates duplicate entries
    }
}
```

The fix:
```rust
// CORRECT: Use index to accumulate into the right slot
if let Some(tcs) = &choice.delta.tool_calls {
    for tc in tcs {
        let idx = tc.index.unwrap_or(tool_calls.len());
        // Grow the vector if needed
        while tool_calls.len() <= idx {
            tool_calls.push(AccumulatedToolCall {
                id: String::new(),
                name: String::new(),
                arguments: String::new(),
            });
        }
        // Only set id and name when present (first chunk)
        if let Some(ref id) = tc.id {
            tool_calls[idx].id = id.clone();
        }
        if let Some(ref f) = tc.function {
            if let Some(ref name) = f.name {
                tool_calls[idx].name = name.clone();
            }
            // Always APPEND arguments, never replace
            if let Some(ref args) = f.arguments {
                tool_calls[idx].arguments.push_str(args);
            }
        }
    }
}
```

The critical insight: `arguments` must be accumulated with `push_str`, not replaced. Each SSE chunk contains a small fragment of the JSON string (like `{"com` then `mand":` then `"ls"}`). Only after the stream ends do you have valid JSON to parse.

There are three different timeouts in reqwest and you likely set the wrong one:

```rust
// This only sets the CONNECT timeout (TCP handshake)
let client = reqwest::Client::builder()
    .connect_timeout(Duration::from_secs(10))
    .build()?;

// This sets the OVERALL request timeout (connect + send + receive)
let client = reqwest::Client::builder()
    .timeout(Duration::from_secs(30))
    .build()?;

// For streaming, NEITHER of these work correctly!
```

For streaming responses (SSE, chunked transfer), `timeout` applies to the entire response body, not per-chunk. A model generating tokens slowly will hit the timeout even though it's actively sending data.

The fix for streaming: use `read_timeout` or implement per-chunk timeout yourself:

```rust
let client = reqwest::Client::builder()
    .connect_timeout(Duration::from_secs(10))
    // Don't set a global timeout for streaming
    .build()?;

// Per-chunk timeout during streaming
let mut stream = resp.bytes_stream();
loop {
    match tokio::time::timeout(
        Duration::from_secs(30),
        stream.next()
    ).await {
        Ok(Some(Ok(chunk))) => {
            // Process chunk
        }
        Ok(Some(Err(e))) => {
            return Err(anyhow::anyhow!("stream read error: {}", e));
        }
        Ok(None) => break, // Stream ended
        Err(_) => {
            return Err(anyhow::anyhow!(
                "inference stalled: no data received for 30 seconds"
            ));
        }
    }
}
```

This gives you a 30-second timeout between chunks, which is what you actually want: "alert me if the model stops producing tokens for 30 seconds" rather than "kill the whole response after 30 seconds total."

The default reqwest `Client` has no connection pool limit per host, but the underlying `hyper` connector defaults to keeping idle connections alive. If your inference server is slow and you're spawning many concurrent requests, you'll run out of connections.

Diagnosis -- add this to confirm:
```rust
// Check if requests are hanging at the connection level
let start = std::time::Instant::now();
let resp = client.get(url).send().await?;
eprintln!("Connection acquired in {:?}", start.elapsed());
// If this takes seconds, your pool is exhausted
```

Fix:
```rust
use reqwest::Client;
use std::time::Duration;

let client = Client::builder()
    // Limit concurrent connections to the inference server
    .pool_max_idle_per_host(10)
    // Don't keep idle connections forever
    .pool_idle_timeout(Duration::from_secs(30))
    // Fail fast if pool is exhausted rather than queueing forever
    .connect_timeout(Duration::from_secs(5))
    .build()?;
```

But the real fix is architectural. Don't fire 50 concurrent requests at a local model server -- it can only run one inference at a time. Use a semaphore:

```rust
use tokio::sync::Semaphore;

static INFERENCE_SEMAPHORE: once_cell::sync::Lazy<Semaphore> =
    once_cell::sync::Lazy::new(|| Semaphore::new(2)); // 2 concurrent inferences max

pub async fn infer(client: &Client, prompt: &str) -> Result<String> {
    let _permit = INFERENCE_SEMAPHORE.acquire().await
        .map_err(|_| anyhow::anyhow!("inference semaphore closed"))?;

    client.post("http://localhost:8411/v1/completions")
        .json(&serde_json::json!({"prompt": prompt}))
        .send()
        .await?
        .json()
        .await
        .context("failed to parse inference response")
}
```

The semaphore prevents pool exhaustion by limiting concurrency at the application level. For a local model server, 1-2 concurrent requests is usually optimal.

Create a typed request builder that encodes the content type at the type level:

```rust
use anyhow::{Context, Result};
use serde::Serialize;

pub struct ApiRequest<'a> {
    client: &'a reqwest::Client,
    builder: reqwest::RequestBuilder,
}

impl<'a> ApiRequest<'a> {
    pub fn new(client: &'a reqwest::Client, method: reqwest::Method, url: &str) -> Self {
        Self {
            client,
            builder: client.request(method, url),
        }
    }

    /// Send JSON body. Sets Content-Type: application/json.
    pub fn json_body<T: Serialize>(mut self, body: &T) -> Self {
        self.builder = self.builder
            .header("Content-Type", "application/json")
            .json(body);
        self
    }

    /// Send form-encoded body. Sets Content-Type: application/x-www-form-urlencoded.
    /// Only use for OAuth token endpoints.
    pub fn form_body<T: Serialize>(mut self, body: &T) -> Self {
        self.builder = self.builder.form(body);
        self
    }

    pub fn bearer_auth(mut self, token: &str) -> Self {
        self.builder = self.builder.bearer_auth(token);
        self
    }

    pub async fn send(self) -> Result<reqwest::Response> {
        let resp = self.builder.send().await.context("request failed")?;
        let status = resp.status();
        if !status.is_success() {
            let body = resp.text().await.unwrap_or_default();
            anyhow::bail!("HTTP {}: {}", status.as_u16(), body);
        }
        Ok(resp)
    }
}

// API methods become:
pub async fn create_completion(&self, req: &CompletionRequest) -> Result<CompletionResponse> {
    ApiRequest::new(&self.client, reqwest::Method::POST, &self.completions_url())
        .bearer_auth(&self.token)
        .json_body(req)  // Can't accidentally use form_body for API calls
        .send()
        .await?
        .json()
        .await
        .context("failed to parse completion response")
}
```

The wrapper makes the intent explicit. You could go further and use Rust's type system to make `form_body` only available for specific endpoint types, but the named-method approach catches 99% of mistakes.

You're missing the flush at stream end. SSE parsers and streaming tool call parsers buffer content to handle partial boundaries, but that buffer needs to be drained when the stream closes:

```rust
// WRONG: Only processes complete events
while let Some(chunk) = stream.next().await {
    let chunk = chunk?;
    for event in parser.feed(&chunk) {
        handle_event(event);
    }
}
// The last partial buffer is silently lost!

// CORRECT: Flush after the stream ends
while let Some(chunk) = stream.next().await {
    let chunk = chunk?;
    for event in parser.feed(&chunk) {
        handle_event(event);
    }
}
// Drain any remaining buffered content
for event in parser.flush() {
    handle_event(event);
}
```

The flush implementation should emit whatever is buffered:
```rust
pub fn flush(&mut self) -> Vec<StreamEvent> {
    let mut events = Vec::new();
    if self.inside_tool_call {
        self.tool_call_buffer.push_str(&self.buffer);
        if !self.tool_call_buffer.is_empty() {
            events.push(StreamEvent::ToolCallPartial(
                self.tool_call_buffer.clone()
            ));
        }
    } else if !self.buffer.is_empty() {
        events.push(StreamEvent::Text(self.buffer.clone()));
    }
    self.buffer.clear();
    self.tool_call_buffer.clear();
    self.inside_tool_call = false;
    events
}
```

This is such a common bug that I'd recommend making it a compile-time guarantee: make `flush()` consume `self` so the parser can't be used after flushing, and have the stream processing function always call it.

No, this is insufficient for clients to handle errors programmatically. Here's a better structure:

```rust
#[derive(serde::Serialize)]
pub struct ApiError {
    pub error: ErrorBody,
}

#[derive(serde::Serialize)]
pub struct ErrorBody {
    /// Machine-readable error code (e.g., "rate_limited", "invalid_request")
    pub code: String,
    /// Human-readable description
    pub message: String,
    /// HTTP status code (duplicated for convenience in error handlers)
    pub status: u16,
    /// Optional: which field caused the error
    #[serde(skip_serializing_if = "Option::is_none")]
    pub param: Option<String>,
    /// Optional: request ID for support/debugging
    #[serde(skip_serializing_if = "Option::is_none")]
    pub request_id: Option<String>,
}

impl ApiError {
    pub fn bad_request(message: impl Into<String>) -> Self {
        Self { error: ErrorBody {
            code: "invalid_request".into(),
            message: message.into(),
            status: 400,
            param: None,
            request_id: None,
        }}
    }

    pub fn rate_limited(retry_after_secs: u64) -> Self {
        Self { error: ErrorBody {
            code: "rate_limited".into(),
            message: format!("Too many requests. Retry after {} seconds.", retry_after_secs),
            status: 429,
            param: None,
            request_id: None,
        }}
    }
}
```

Key principles: (1) `code` is for machines, `message` is for humans -- never parse the message string programmatically. (2) Always include the HTTP status in the body so clients logging the response body have the full picture. (3) `param` tells the client exactly which input was wrong. (4) `request_id` is essential for debugging production issues.

Use cursor-based for anything with concurrent writes. Offset-based breaks when items are inserted or deleted between page fetches.

```rust
use serde::{Deserialize, Serialize};

#[derive(Deserialize)]
pub struct ListParams {
    /// Opaque cursor from a previous response
    pub cursor: Option<String>,
    /// Max items per page (default 20, max 100)
    pub limit: Option<u32>,
}

#[derive(Serialize)]
pub struct ListResponse<T: Serialize> {
    pub data: Vec<T>,
    /// If present, pass this to get the next page
    #[serde(skip_serializing_if = "Option::is_none")]
    pub next_cursor: Option<String>,
    /// Whether more items exist beyond this page
    pub has_more: bool,
}

impl ListParams {
    pub fn effective_limit(&self) -> u32 {
        self.limit.unwrap_or(20).min(100)
    }
}

// Cursor encoding: base64(json({"id": last_id, "ts": last_timestamp}))
// The cursor is opaque to the client -- they just pass it back.
pub fn encode_cursor(last_id: &str, timestamp: i64) -> String {
    use base64::Engine;
    let json = serde_json::json!({"id": last_id, "ts": timestamp});
    base64::engine::general_purpose::URL_SAFE_NO_PAD
        .encode(json.to_string().as_bytes())
}

pub fn decode_cursor(cursor: &str) -> anyhow::Result<(String, i64)> {
    use base64::Engine;
    let bytes = base64::engine::general_purpose::URL_SAFE_NO_PAD
        .decode(cursor)
        .map_err(|_| anyhow::anyhow!("invalid cursor"))?;
    let value: serde_json::Value = serde_json::from_slice(&bytes)
        .map_err(|_| anyhow::anyhow!("invalid cursor"))?;
    let id = value["id"].as_str()
        .ok_or_else(|| anyhow::anyhow!("invalid cursor"))?.to_string();
    let ts = value["ts"].as_i64()
        .ok_or_else(|| anyhow::anyhow!("invalid cursor"))?;
    Ok((id, ts))
}
```

The SQL query becomes `WHERE (timestamp, id) < (?ts, ?id) ORDER BY timestamp DESC, id DESC LIMIT ?limit + 1`. Fetch one extra row to determine `has_more`, then truncate to the requested limit.

Yes, always include rate limit headers. Clients that respect them will self-throttle, reducing your server load:

```rust
use axum::http::HeaderMap;
use std::time::{SystemTime, UNIX_EPOCH};

pub struct RateLimitInfo {
    pub limit: u32,       // Max requests per window
    pub remaining: u32,   // Requests left in current window
    pub reset_at: u64,    // Unix timestamp when window resets
}

pub fn rate_limit_headers(info: &RateLimitInfo) -> HeaderMap {
    let mut headers = HeaderMap::new();

    // Standard headers (draft RFC 7231 extension, widely adopted)
    headers.insert("x-ratelimit-limit",
        info.limit.to_string().parse().unwrap());
    headers.insert("x-ratelimit-remaining",
        info.remaining.to_string().parse().unwrap());
    headers.insert("x-ratelimit-reset",
        info.reset_at.to_string().parse().unwrap());

    // When rate limited, also set Retry-After (RFC 7231)
    if info.remaining == 0 {
        let now = SystemTime::now()
            .duration_since(UNIX_EPOCH).unwrap().as_secs();
        let retry_after = info.reset_at.saturating_sub(now);
        headers.insert("retry-after",
            retry_after.to_string().parse().unwrap());
    }

    headers
}

// Middleware usage with axum:
async fn rate_limit_middleware(
    req: axum::extract::Request,
    next: axum::middleware::Next,
) -> axum::response::Response {
    let info = check_rate_limit(&req); // Your rate limiter

    if info.remaining == 0 {
        let mut resp = axum::response::Response::new(
            axum::body::Body::from(
                serde_json::to_string(&ApiError::rate_limited(
                    info.reset_at - now()
                )).unwrap()
            )
        );
        *resp.status_mut() = axum::http::StatusCode::TOO_MANY_REQUESTS;
        resp.headers_mut().extend(rate_limit_headers(&info));
        return resp;
    }

    let mut resp = next.run(req).await;
    resp.headers_mut().extend(rate_limit_headers(&info));
    resp
}
```

Include the headers on every response, not just 429s. This lets well-behaved clients slow down before hitting the limit. The `retry-after` header on 429 responses is especially important -- without it, clients will retry immediately in a tight loop.

Use URL-path versioning (`/v1/resource`). It's the simplest to implement, test, and debug:

